const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');

function getDayOfWeekId(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return null;
  const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  return days[d.getUTCDay()];
}

// All tour bookings with a valid cruise
const tourBookings = cartItems.filter(i => i && (i.item_type === 'tour_booking' || i.item_type === 'charter_booking') && i.cruise_tour_id);

// Base qualifying bookings: sunset/evening category, drinks included
const baseQualifying = tourBookings.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;
  const cats = cruise.categories || [];
  const tod = cruise.time_of_day_tags || [];
  const feats = cruise.features || [];
  const hasSunsetEveningCat = cats.includes('sunset_evening');
  const hasSunsetOrEveningTag = tod.some(t => t === 'sunset' || t === 'evening');
  const hasDrinks = feats.includes('drinks_included');
  return cruise.pricing_model === 'per_person' && hasSunsetEveningCat && hasSunsetOrEveningTag && hasDrinks;
});

// CP1 (0.4): User added at least one qualifying sunset/evening cruise with drinks
checkpoints.push({ passed: baseQualifying.length > 0, weight: 0.4 });

// Stricter: correct pax, price <= 40/adult, Friday in June
const fullyQualifying = baseQualifying.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;

  const adults = Number(b.adult_count || 0);
  const children = Number(b.child_count || 0);
  if (adults !== 2 || children !== 0) return false;

  const pricePerAdult = typeof b.unit_price_adult === 'number' ? b.unit_price_adult : (cruise.base_price_adult || 0);
  if (!(pricePerAdult > 0 && pricePerAdult <= 40)) return false;

  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  const month = d.getUTCMonth() + 1; // 1-12
  const dowId = getDayOfWeekId(dateStr);
  return month === 6 && dowId === 'friday';
});

// CP2 (0.6): At least one booking meets ALL task constraints (2 adults, <=$40/adult, Friday in June)
checkpoints.push({ passed: fullyQualifying.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');
const nextMonthDate = new Date(baselineDate.getTime());
nextMonthDate.setUTCMonth(nextMonthDate.getUTCMonth() + 1);

function getDayOfWeekId(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return null;
  const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  return days[d.getUTCDay()];
}

function parseTimeToMinutes(t) {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length < 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
}

// All 1-adult sightseeing daytime tour bookings
const tourBookings = cartItems.filter(i => i && i.item_type === 'tour_booking' && i.cruise_tour_id);

const daytimeSightseeing = tourBookings.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;
  const cats = cruise.categories || [];
  const tod = cruise.time_of_day_tags || [];

  const isSightseeingCat = cats.includes('sightseeing');
  const isDaytimeTag = tod.some(t => t === 'morning' || t === 'afternoon');
  const adults = Number(b.adult_count || 0);
  const children = Number(b.child_count || 0);
  const seniors = Number(b.senior_count || 0);
  const guests = Number(b.guest_count || 0);
  if (!(adults === 1 && children === 0 && seniors === 0 && guests === 0)) return false;

  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  if (!(d >= baselineDate && d < nextMonthDate)) return false;

  const dowId = getDayOfWeekId(dateStr);
  return cruise.pricing_model === 'per_person' && isSightseeingCat && isDaytimeTag && dowId === 'saturday';
});

// Build all unique pairs of such bookings
const basicPairs = [];
for (let i = 0; i < daytimeSightseeing.length; i++) {
  for (let j = i + 1; j < daytimeSightseeing.length; j++) {
    const a = daytimeSightseeing[i];
    const b = daytimeSightseeing[j];
    const cruiseA = cruises.find(c => c.id === a.cruise_tour_id);
    const cruiseB = cruises.find(c => c.id === b.cruise_tour_id);
    if (!cruiseA || !cruiseB) continue;

    // Different tours
    if (cruiseA.id === cruiseB.id) continue;

    const dateA = String(a.date).slice(0, 10);
    const dateB = String(b.date).slice(0, 10);
    // Same calendar date
    if (dateA !== dateB) continue;

    // Passed all base constraints
    basicPairs.push({ a, b });
  }
}

// CP1 (0.5): At least one pair of different sightseeing daytime tours for 1 adult on the same Saturday in the next month
checkpoints.push({ passed: basicPairs.length > 0, weight: 0.5 });

// Now require >=2h time gap and combined total <= 120
const fullyQualifyingPairs = basicPairs.filter(pair => {
  const { a, b } = pair;
  const timeA = parseTimeToMinutes(a.departure_time);
  const timeB = parseTimeToMinutes(b.departure_time);
  if (timeA === null || timeB === null) return false;
  const gap = Math.abs(timeA - timeB);
  if (gap < 120) return false;

  const total = Number(a.line_subtotal || 0) + Number(b.line_subtotal || 0);
  return total <= 120;
});

// CP2 (0.5): At least one pair also meets the >=2h time gap and combined budget <= $120
checkpoints.push({ passed: fullyQualifyingPairs.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');

function getDayOfWeekId(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return null;
  const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  return days[d.getUTCDay()];
}

// All charter bookings
const charterBookings = cartItems.filter(i => i && i.item_type === 'charter_booking' && i.cruise_tour_id);

// Base conditions: private charter, evening/sunset, 10 guests, September weekend, under $900
const baseQualifying = charterBookings.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;
  if (cruise.product_type !== 'private_charter') return false;
  if (cruise.pricing_model !== 'per_charter') return false;

  const cats = cruise.categories || [];
  const tod = cruise.time_of_day_tags || [];
  const hasPrivateCat = cats.includes('private_charters');
  const hasEveningTag = tod.some(t => t === 'evening' || t === 'sunset');
  if (!hasPrivateCat || !hasEveningTag) return false;

  const guests = Number(b.guest_count || 0);
  if (guests !== 10) return false;

  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  const month = d.getUTCMonth() + 1;
  const dowId = getDayOfWeekId(dateStr);
  const isWeekend = dowId === 'saturday' || dowId === 'sunday';
  if (!(month === 9 && isWeekend)) return false;

  const pricePerCharter = typeof b.unit_price_per_charter === 'number' ? b.unit_price_per_charter : (cruise.base_price_per_charter || 0);
  if (!(pricePerCharter > 0 && pricePerCharter < 900)) return false;

  // Capacity sanity check if defined
  if (typeof cruise.min_group_size === 'number' && guests < cruise.min_group_size) return false;
  if (typeof cruise.max_group_size === 'number' && guests > cruise.max_group_size) return false;

  // At least 3 hours
  if (typeof cruise.duration_minutes === 'number' && cruise.duration_minutes < 180) return false;

  return true;
});

// CP1 (0.4): At least one qualifying evening private charter for 10 guests in September weekend under $900 and >=3h
checkpoints.push({ passed: baseQualifying.length > 0, weight: 0.4 });

// Determine the longest available qualifying charter in the catalog (under same basic constraints, but not tied to date)
const allQualifyingCharters = cruises.filter(c => {
  if (!c) return false;
  if (c.product_type !== 'private_charter') return false;
  if (c.pricing_model !== 'per_charter') return false;
  const cats = c.categories || [];
  const tod = c.time_of_day_tags || [];
  const hasPrivateCat = cats.includes('private_charters');
  const hasEveningTag = tod.some(t => t === 'evening' || t === 'sunset');
  if (!hasPrivateCat || !hasEveningTag) return false;
  if (typeof c.duration_minutes !== 'number' || c.duration_minutes < 180) return false;
  const price = c.base_price_per_charter || 0;
  if (!(price > 0 && price < 900)) return false;
  return true;
});

let maxDuration = null;
allQualifyingCharters.forEach(c => {
  if (typeof c.duration_minutes !== 'number') return;
  if (maxDuration === null || c.duration_minutes > maxDuration) {
    maxDuration = c.duration_minutes;
  }
});

const longestCharterIds = (maxDuration === null) ? [] : allQualifyingCharters.filter(c => c.duration_minutes === maxDuration).map(c => c.id);

const choseLongest = baseQualifying.some(b => longestCharterIds.includes(b.cruise_tour_id));

// CP2 (0.6): Among qualifying bookings, user selected a charter with the maximum duration among all qualifying options
checkpoints.push({ passed: longestCharterIds.length > 0 && choseLongest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const giftCards = JSON.parse(localStorage.getItem('gift_card_items') || '[]');
const templates = JSON.parse(localStorage.getItem('gift_card_templates') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const anyCruiseTemplateIds = templates.filter(t => t && t.default_applies_to_scope === 'all_cruises').map(t => t.id);

// Gift cards that match amount, scope, and have non-empty recipient/sender/message
const baseMatching = giftCards.filter(gc => {
  if (!gc) return false;
  if (Number(gc.amount || 0) !== 150) return false;
  if (gc.currency !== 'USD') return false;
  if (gc.applies_to_scope !== 'all_cruises') return false;
  if (!gc.recipient_name || !gc.sender_name) return false;
  if (typeof gc.message !== 'string' || gc.message.trim().length === 0) return false;
  // Must be currently in cart and linked from a cart item
  const linkedCartItem = cartItems.find(ci => ci && ci.item_type === 'gift_card' && ci.gift_card_item_id === gc.id);
  if (!linkedCartItem) return false;
  if (Number(linkedCartItem.line_subtotal || 0) !== 150) return false;
  return true;
});

// CP1 (0.6): At least one $150 all-cruises gift card with recipient, sender, and message is in the cart
checkpoints.push({ passed: baseMatching.length > 0, weight: 0.6 });

// Further require that it was created from an "any cruise" style template
const fromAnyCruiseTemplate = baseMatching.some(gc => anyCruiseTemplateIds.includes(gc.template_id));

// CP2 (0.4): At least one such card is based on a template whose default scope is all_cruises (any cruise gift card)
checkpoints.push({ passed: anyCruiseTemplateIds.length > 0 && fromAnyCruiseTemplate, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

