  const children = Number(b.child_count || 0);
  if (!(adults === 2 && children === 1)) return false;
  return hasFamilyCat && hasLunch && isFamilyFriendly;
});

// CP1 (0.5): At least one booking of a lunch-included family-friendly cruise for 2 adults and 1 child
checkpoints.push({ passed: baseQualifying.length > 0, weight: 0.5 });

// Stricter: Sunday within next month, depart before 14:00, total <= 200
const fullyQualifying = baseQualifying.filter(b => {
  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  if (!(d >= baselineDate && d < nextMonthDate)) return false;
  const dowId = getDayOfWeekId(dateStr);
  if (dowId !== 'sunday') return false;

  const departMinutes = parseTimeToMinutes(b.departure_time);
  if (departMinutes === null || departMinutes >= (14 * 60)) return false;

  const total = Number(b.line_subtotal || 0);
  if (!(total > 0 && total < 200 + 1e-6)) return false;

  return true;
});

// CP2 (0.5): At least one booking also meets Sunday, date window, departure time, and budget constraints
checkpoints.push({ passed: fullyQualifying.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cartObj = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');

function getDayOfWeekId(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return null;
  const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  return days[d.getUTCDay()];
}

// Determine all catalog cruises that meet dinner + live music + duration + price constraints
const allQualifyingCruises = cruises.filter(c => {
  if (!c) return false;
  const cats = c.categories || [];
  const feats = c.features || [];
  const hasDinnerCat = cats.includes('dinner_cruises');
  const hasLiveMusic = feats.includes('live_music');
  if (!hasDinnerCat || !hasLiveMusic) return false;
  if (c.pricing_model !== 'per_person') return false;
  if (typeof c.duration_minutes !== 'number' || c.duration_minutes < 150) return false; // 2.5h
  const price = c.base_price_adult || 0;
  if (!(price > 0 && price <= 120)) return false;
  return true;
});

let maxRating = null;
allQualifyingCruises.forEach(c => {
  const r = typeof c.average_rating === 'number' ? c.average_rating : 0;
  if (maxRating === null || r > maxRating) maxRating = r;
});

const topCruiseIds = (maxRating === null) ? [] : allQualifyingCruises.filter(c => (c.average_rating || 0) === maxRating).map(c => c.id);

// Bookings: 2 adults on qualifying dinner cruises on a Saturday, price <=120
const tourBookings = cartItems.filter(i => i && i.item_type === 'tour_booking' && i.cruise_tour_id);

const qualifyingBookings = tourBookings.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;
  if (!allQualifyingCruises.some(c => c.id === cruise.id)) return false;

  const adults = Number(b.adult_count || 0);
  const children = Number(b.child_count || 0);
  const seniors = Number(b.senior_count || 0);
  if (!(adults === 2 && children === 0 && seniors === 0)) return false;

  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  if (!(d >= baselineDate)) return false; // next available Saturday or later
  const dowId = getDayOfWeekId(dateStr);
  if (dowId !== 'saturday') return false;

  const pricePerAdult = typeof b.unit_price_adult === 'number' ? b.unit_price_adult : (cruise.base_price_adult || 0);
  if (!(pricePerAdult > 0 && pricePerAdult <= 120)) return false;

  return true;
});

// CP1 (0.5): At least one booking matches live-music dinner cruise, duration>=2.5h, price<=120/adult, for 2 adults on a Saturday
checkpoints.push({ passed: qualifyingBookings.length > 0, weight: 0.5 });

// CP2 (0.5): Among those, user picked a highest-rated qualifying cruise AND applied SUMMER10 promo code
const usedTopRated = qualifyingBookings.some(b => topCruiseIds.includes(b.cruise_tour_id));
const promoApplied = cartObj && typeof cartObj === 'object' && String(cartObj.applied_promo_code || '').toUpperCase() === 'SUMMER10';
checkpoints.push({ passed: topCruiseIds.length > 0 && usedTopRated && promoApplied, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');
const sevenDaysOut = new Date(baselineDate.getTime());
sevenDaysOut.setUTCDate(sevenDaysOut.getUTCDate() + 7);

function parseTimeToMinutes(t) {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length < 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
}

// Determine catalog cruises that match departure, duration, and adult price constraints
const catalogCandidates = cruises.filter(c => {
  if (!c) return false;
  if (c.departure_location_id !== 'old_town_pier') return false;
  if (c.pricing_model !== 'per_person') return false;
  const dur = c.duration_minutes || 0;
  if (!(dur >= 60 && dur <= 90)) return false;
  const price = c.base_price_adult || 0;
  if (!(price >= 30 && price <= 60)) return false;
  return true;
});

// Compute the earliest departure time among these cruises based on their time_slots or default_start_time
let globalEarliestMinutes = null;
let globalEarliestTimeStr = null;
let globalEarliestCruiseIds = [];

catalogCandidates.forEach(c => {
  const slots = timeSlots.filter(ts => ts && ts.cruise_tour_id === c.id && ts.is_active);
  let cruiseEarliestMinutes = null;
  let cruiseEarliestStr = null;
  if (slots.length > 0) {
    slots.forEach(ts => {
      const m = parseTimeToMinutes(ts.start_time);
      if (m === null) return;
      if (cruiseEarliestMinutes === null || m < cruiseEarliestMinutes) {
        cruiseEarliestMinutes = m;
        cruiseEarliestStr = ts.start_time;
      }
    });
  } else if (c.default_start_time) {
    const m = parseTimeToMinutes(c.default_start_time);
    if (m !== null) {
      cruiseEarliestMinutes = m;
      cruiseEarliestStr = c.default_start_time;
    }
  }
  if (cruiseEarliestMinutes === null) return;

  if (globalEarliestMinutes === null || cruiseEarliestMinutes < globalEarliestMinutes) {
    globalEarliestMinutes = cruiseEarliestMinutes;
    globalEarliestTimeStr = cruiseEarliestStr;
    globalEarliestCruiseIds = [c.id];
  } else if (cruiseEarliestMinutes === globalEarliestMinutes) {
    globalEarliestCruiseIds.push(c.id);
  }
});

// Cart bookings: 3 adults on a qualifying cruise, within next 7 days, price 30-60/adult
const tourBookings = cartItems.filter(i => i && i.item_type === 'tour_booking' && i.cruise_tour_id);

const baseQualifyingBookings = tourBookings.filter(b => {
  const cruise = cruises.find(c => c.id === b.cruise_tour_id);
  if (!cruise) return false;
  if (!catalogCandidates.some(c => c.id === cruise.id)) return false;

  const adults = Number(b.adult_count || 0);
  const children = Number(b.child_count || 0);
  const seniors = Number(b.senior_count || 0);
  const guests = Number(b.guest_count || 0);
  if (!(adults === 3 && children === 0 && seniors === 0 && guests === 0)) return false;

  if (!b.date) return false;
  const dateStr = String(b.date).slice(0, 10);
  const d = new Date(dateStr + 'T00:00:00Z');
  if (isNaN(d.getTime())) return false;
  if (!(d >= baselineDate && d <= sevenDaysOut)) return false;

  const pricePerAdult = typeof b.unit_price_adult === 'number' ? b.unit_price_adult : (cruise.base_price_adult || 0);
  if (!(pricePerAdult >= 30 && pricePerAdult <= 60)) return false;

  // Duration is guaranteed by catalogCandidates filter
  return true;
});

// CP1 (0.4): At least one booking matches departure, duration, date window, pax, and price constraints
checkpoints.push({ passed: baseQualifyingBookings.length > 0, weight: 0.4 });

// CP2 (0.6): Among these, user chose the earliest available departure time among all qualifying catalog options
const choseEarliest = baseQualifyingBookings.some(b => {
  if (!globalEarliestTimeStr) return false;
  if (!globalEarliestCruiseIds.includes(b.cruise_tour_id)) return false;
  return String(b.departure_time || '') === globalEarliestTimeStr;
});

checkpoints.push({ passed: globalEarliestTimeStr !== null && choseEarliest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let viewedIdsRaw = localStorage.getItem('task8_viewedCruiseIds');
let viewedIds = [];
try {
  viewedIds = viewedIdsRaw ? JSON.parse(viewedIdsRaw) : [];
  if (!Array.isArray(viewedIds)) viewedIds = [];
} catch (e) {
  viewedIds = [];
}

const cruises = JSON.parse(localStorage.getItem('cruise_tours') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');
const nextMonthDate = new Date(baselineDate.getTime());
nextMonthDate.setUTCMonth(nextMonthDate.getUTCMonth() + 1);

// Qualifying sightseeing cruises under $75 with audio guide and >=24h free cancellation
const qualifyingCruises = cruises.filter(c => {
  if (!c) return false;
  if (c.pricing_model !== 'per_person') return false;
  const cats = c.categories || [];
  const feats = c.features || [];
  const hasSightseeingCat = cats.includes('sightseeing');
  const hasAudio = feats.includes('audio_guide');
  const hasFreeCancellationFeature = feats.includes('free_cancellation');
  const cutoff = typeof c.free_cancellation_cutoff_hours === 'number' ? c.free_cancellation_cutoff_hours : null;
  const meetsCutoff = cutoff !== null ? cutoff >= 24 : hasFreeCancellationFeature;
  const price = c.base_price_adult || 0;
  if (!(hasSightseeingCat && hasAudio && meetsCutoff && price < 75)) return false;
  return true;
});

